import React, { createContext, useContext, useState, useEffect, useCallback, useMemo, Suspense, lazy } from 'react';
import { BrowserRouter, Routes, Route, NavLink, useLocation, Navigate } from 'react-router-dom';
import {
  LayoutDashboard, HardDrive, Database,
  Shield, DollarSign, Search, Activity,
  ChevronRight, Boxes, CloudCog,
  Globe, Server, Container, KeyRound, AppWindow,
  Layers, GitBranch, ChevronsDownUp, ChevronsUpDown,
  Settings, LogOut,
} from 'lucide-react';
import { QueryClient, QueryClientProvider, useQuery } from '@tanstack/react-query';
import { fetchSubscriptions, fetchCostSummary } from './api/azure';
import { getStoredToken } from './api/auth';
import { getErrorMessage } from './api/errors';
import usePersistedState from './hooks/usePersistedState';
import { NAV_GROUPS, DEFAULT_NAV_OPEN, groupForPath } from './config/nav';
import MobileHeader from './components/MobileHeader';
import AssetIcon from './components/AssetIcon';
import ErrorBoundary from './components/ErrorBoundary';
import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider, useAuth } from './context/AuthContext';
import { LoadingState } from './components/QueryStates';
import { PAGE_ICONS, NAV_GROUP_ICONS, iconForRoute } from './config/assetIcons';

const Dashboard = lazy(() => import('./pages/Dashboard'));
const CostExplorer = lazy(() => import('./pages/CostExplorer'));
const Findings = lazy(() => import('./pages/Findings'));
const VirtualMachines = lazy(() => import('./pages/VirtualMachines'));
const AKSClusters = lazy(() => import('./pages/AKSClusters'));
const EngineConfig = lazy(() => import('./pages/EngineConfig'));
const AdminOptimization = lazy(() => import('./pages/AdminOptimization'));
const RunHistory = lazy(() => import('./pages/RunHistory'));
const ResourceList = lazy(() => import('./pages/ResourceList'));
const SettingsPage = lazy(() => import('./pages/Settings'));
const Login = lazy(() => import('./pages/Login'));

const qc = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 60_000,
      retry: 1,
      refetchOnWindowFocus: false,
    },
    mutations: {
      retry: 0,
    },
  },
});
export const AppCtx = createContext({});

function NavIcon({ iconKey, src, fallback: Fallback, size = 14 }) {
  return <AssetIcon iconKey={iconKey} src={src} size={size} fallback={<Fallback size={size} />} />;
}

const PAGE_TITLES = {
  '/': 'Dashboard',
  '/costs': 'Cost explorer',
  '/findings': 'Findings',
  '/engine': 'Optimization rules',
  '/admin/optimization': 'Optimization center',
  '/history': 'Run history',
  '/vms': 'Virtual machines',
  '/disks': 'Managed disks',
  '/aks': 'AKS clusters',
  '/acr': 'Container registries',
  '/appservices': 'App services',
  '/storage': 'Storage accounts',
  '/publicips': 'Public IPs',
  '/loadbalancers': 'Load balancers',
  '/appgateways': 'App gateways',
  '/nsgs': 'Network security groups',
  '/sql': 'SQL servers',
  '/cosmosdb': 'Cosmos DB',
  '/postgresql': 'PostgreSQL',
  '/keyvaults': 'Key vaults',
  '/settings': 'Settings',
};

function NavGroup({ id, label, iconSrc, color, open, onToggle, children }) {
  return (
    <div className={`nav-group${open ? ' nav-group--open' : ''}`}>
      <button
        type="button"
        className="nav-group-btn"
        onClick={onToggle}
        aria-expanded={open}
        aria-controls={`nav-group-${id}`}
      >
        <span className="nav-group-btn__icon" style={{ color }}>
          <AssetIcon iconKey={iconSrc} size={14} />
        </span>
        <span className="nav-group-btn__label">{label}</span>
        <span className={`nav-group-btn__chevron${open ? ' nav-group-btn__chevron--open' : ''}`}>
          <ChevronRight size={14} />
        </span>
      </button>
      <div id={`nav-group-${id}`} className="nav-group__panel">
        <div className="nav-group__items">{children}</div>
      </div>
    </div>
  );
}

function SidebarNav({ onNavClick }) {
  const location = useLocation();
  const { isAdmin } = useAuth();
  const [groups, setGroups] = usePersistedState('finops-nav-groups', DEFAULT_NAV_OPEN);

  // Auto-expand group containing active route (without collapsing others)
  useEffect(() => {
    const activeGroup = groupForPath(location.pathname);
    if (activeGroup && !groups[activeGroup]) {
      setGroups(prev => ({ ...prev, [activeGroup]: true }));
    }
  }, [location.pathname]); // eslint-disable-line react-hooks/exhaustive-deps

  const toggleGroup = useCallback((id) => {
    setGroups(prev => ({ ...prev, [id]: !prev[id] }));
  }, [setGroups]);

  const allResourceOpen = Object.keys(NAV_GROUPS).every(id => groups[id]);
  const toggleAllResources = () => {
    const next = !allResourceOpen;
    setGroups(prev => {
      const updated = { ...prev };
      Object.keys(NAV_GROUPS).forEach(id => { updated[id] = next; });
      return updated;
    });
  };

  return (
  <div className="sidebar-nav">
    <div className="sidebar-section">Overview</div>
    <NavLink to="/" end className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
      <NavIcon iconKey={PAGE_ICONS.dashboard} fallback={LayoutDashboard} size={16} /> Dashboard
    </NavLink>
    <NavLink to="/costs" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
      <NavIcon src={PAGE_ICONS.costs} fallback={DollarSign} size={16} /> Cost explorer
    </NavLink>
    <NavLink to="/findings" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
      <NavIcon src={PAGE_ICONS.findings} fallback={Activity} size={16} /> Findings
    </NavLink>

    <div className="sidebar-section sidebar-section--row">
      <span>Resources</span>
      <button
        type="button"
        className="sidebar-section__toggle"
        onClick={toggleAllResources}
        title={allResourceOpen ? 'Collapse all' : 'Expand all'}
      >
        {allResourceOpen ? <ChevronsDownUp size={13} /> : <ChevronsUpDown size={13} />}
      </button>
    </div>

    <NavGroup id="compute" label="Compute" iconSrc={NAV_GROUP_ICONS.compute} color="#60a5fa"
      open={!!groups.compute} onToggle={() => toggleGroup('compute')}>
      <NavLink to="/vms" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.vms} fallback={Server} /> Virtual machines
      </NavLink>
      <NavLink to="/disks" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.disks} fallback={HardDrive} /> Managed disks
      </NavLink>
    </NavGroup>

    <NavGroup id="containers" label="Containers" iconSrc={NAV_GROUP_ICONS.containers} color="#a78bfa"
      open={!!groups.containers} onToggle={() => toggleGroup('containers')}>
      <NavLink to="/aks" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.aks} fallback={Boxes} /> AKS clusters
      </NavLink>
      <NavLink to="/acr" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.acr} fallback={Container} /> Container registries
      </NavLink>
    </NavGroup>

    <NavGroup id="appservices" label="App services" iconSrc={NAV_GROUP_ICONS.appservices} color="#22d3ee"
      open={!!groups.appservices} onToggle={() => toggleGroup('appservices')}>
      <NavLink to="/appservices" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.appservices} fallback={AppWindow} /> Web / function apps
      </NavLink>
    </NavGroup>

    <NavGroup id="storage" label="Storage" iconSrc={NAV_GROUP_ICONS.storage} color="#fbbf24"
      open={!!groups.storage} onToggle={() => toggleGroup('storage')}>
      <NavLink to="/storage" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.storage} fallback={HardDrive} /> Storage accounts
      </NavLink>
    </NavGroup>

    <NavGroup id="networking" label="Networking" iconSrc={NAV_GROUP_ICONS.networking} color="#34d399"
      open={!!groups.networking} onToggle={() => toggleGroup('networking')}>
      <NavLink to="/publicips" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.publicips} fallback={Globe} /> Public IPs
      </NavLink>
      <NavLink to="/loadbalancers" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.loadbalancers} fallback={Layers} /> Load balancers
      </NavLink>
      <NavLink to="/appgateways" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.appgateways} fallback={GitBranch} /> App gateways
      </NavLink>
      <NavLink to="/nsgs" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.nsgs} fallback={Shield} /> Network security groups
      </NavLink>
    </NavGroup>

    <NavGroup id="databases" label="Databases" iconSrc={NAV_GROUP_ICONS.databases} color="#f87171"
      open={!!groups.databases} onToggle={() => toggleGroup('databases')}>
      <NavLink to="/sql" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.sql} fallback={Database} /> SQL servers
      </NavLink>
      <NavLink to="/cosmosdb" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.cosmosdb} fallback={Database} /> Cosmos DB
      </NavLink>
      <NavLink to="/postgresql" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.postgresql} fallback={Database} /> PostgreSQL
      </NavLink>
    </NavGroup>

    <NavGroup id="security" label="Security" iconSrc={NAV_GROUP_ICONS.security} color="#fb923c"
      open={!!groups.security} onToggle={() => toggleGroup('security')}>
      <NavLink to="/keyvaults" className={({ isActive }) => `nav-item nav-sub${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.keyvaults} fallback={KeyRound} /> Key vaults
      </NavLink>
    </NavGroup>

    <div className="sidebar-section">Engine</div>
    {isAdmin && (
      <NavLink to="/admin/optimization" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.engine} fallback={CloudCog} size={16} /> Optimization center
      </NavLink>
    )}
    {isAdmin && (
      <NavLink to="/engine" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon src={PAGE_ICONS.engine} fallback={CloudCog} size={16} /> Engine rules
      </NavLink>
    )}
    <NavLink to="/history" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
      <NavIcon src={PAGE_ICONS.history} fallback={Search} size={16} /> Run history
    </NavLink>

    <div className="sidebar-section">System</div>
    {isAdmin && (
      <NavLink to="/settings" className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`} onClick={onNavClick}>
        <NavIcon iconKey={PAGE_ICONS.settings} fallback={Settings} size={16} /> Settings
      </NavLink>
    )}
  </div>
  );
}

function Shell() {
  const {
    subscription, setSubscription, subscriptionOptions,
    loading, subscriptionError,
    billingCurrency,
  } = useContext(AppCtx);
  const { user, logout, isAdmin } = useAuth();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);
  const subName = subscriptionOptions.find(s => s.subscriptionId === subscription)?.displayName;
  const pageTitle = PAGE_TITLES[location.pathname] || 'Azure FinOps';

  const closeMobile = useCallback(() => setMobileOpen(false), []);

  useEffect(() => {
    closeMobile();
  }, [location.pathname, closeMobile]);

  useEffect(() => {
    document.body.style.overflow = mobileOpen ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [mobileOpen]);

  return (
    <div className={`app-shell${mobileOpen ? ' app-shell--nav-open' : ''}`}>
      <div
        className="sidebar-backdrop"
        onClick={closeMobile}
        aria-hidden={!mobileOpen}
      />

      <aside className="sidebar" aria-label="Main navigation">
        <div className="sidebar-logo">
          <div className="sidebar-logo__icon">
            <AssetIcon iconKey={PAGE_ICONS.logo} size={20} fallback={<CloudCog size={18} />} />
          </div>
          <div className="sidebar-logo__text">Azure<span>FinOps</span></div>
        </div>

        <div className="sidebar-sub-picker">
          <div className="topbar-label icon-inline">
            <AssetIcon iconKey={PAGE_ICONS.subscription} size={12} />
            Subscription
          </div>
          {loading ? (
            <div className="sidebar-loading">
              <div className="spin" style={{ width: 14, height: 14, borderWidth: 2 }} />
              Loading…
            </div>
          ) : subscriptionError ? (
            <div className="sidebar-error" role="alert" style={{ fontSize: '0.75rem', color: 'var(--danger)', lineHeight: 1.4 }}>
              {subscriptionError}
            </div>
          ) : subscriptionOptions.length === 0 ? (
            <div className="sidebar-empty-sub" role="status">
              No subscriptions in the database yet.
              {isAdmin && (
                <span> Set a default subscription in Settings, or run Sync from Azure after entering a subscription ID.</span>
              )}
            </div>
          ) : (
            <select
              className="select-field"
              value={subscription}
              onChange={e => setSubscription(e.target.value)}
            >
              <option value="">Select subscription</option>
              {subscriptionOptions.map(s => (
                <option key={s.subscriptionId} value={s.subscriptionId}>
                  {s.displayName || s.subscriptionId}
                </option>
              ))}
            </select>
          )}
          {subscription && billingCurrency && (
            <div className="sidebar-currency-hint">
              Costs shown in <strong>{billingCurrency}</strong> (Azure billing currency)
            </div>
          )}
        </div>

        <SidebarNav onNavClick={closeMobile} />

        <div className="sidebar-footer">
          <div className="sidebar-footer__user">
            <span className="sidebar-footer__name" title={user?.username}>{user?.display_name || user?.username}</span>
            {user?.role && <span className="sidebar-footer__role">{user.role}</span>}
          </div>
          <button type="button" className="sidebar-footer__logout" onClick={logout} title="Sign out">
            <LogOut size={14} />
            Sign out
          </button>
          {subName && <span className="sidebar-footer__sub" title={subName}>{subName}</span>}
        </div>
      </aside>

      <div className="main-column">
        <MobileHeader
          open={mobileOpen}
          onToggle={() => setMobileOpen(o => !o)}
          title={pageTitle}
          iconKey={iconForRoute(location.pathname)}
        />
        <main className="main-content">
          <ErrorBoundary>
            <Suspense fallback={<LoadingState message="Loading page…" />}>
              <Routes>
            <Route path="/"          element={<Dashboard />} />
            <Route path="/costs"     element={<CostExplorer />} />
            <Route path="/findings"  element={<Findings />} />
            <Route path="/vms"       element={<VirtualMachines />} />
            <Route path="/aks"       element={<AKSClusters />} />
            <Route path="/engine"    element={<ProtectedRoute adminOnly><EngineConfig /></ProtectedRoute>} />
            <Route path="/admin/optimization" element={<ProtectedRoute adminOnly><AdminOptimization /></ProtectedRoute>} />
            <Route path="/history"   element={<RunHistory />} />
            <Route path="/settings"  element={<ProtectedRoute adminOnly><SettingsPage /></ProtectedRoute>} />
            <Route path="/disks"         element={<ResourceList title="Managed disks"           apiPath="/resources/disks"         iconSrc={PAGE_ICONS.disks} />} />
            <Route path="/acr"           element={<ResourceList title="Container registries"    apiPath="/resources/acr"           iconSrc={PAGE_ICONS.acr} />} />
            <Route path="/appservices"   element={<ResourceList title="Web / function apps"     apiPath="/resources/appservices"   iconSrc={PAGE_ICONS.appservices} />} />
            <Route path="/storage"       element={<ResourceList title="Storage accounts"        apiPath="/resources/storage"       iconSrc={PAGE_ICONS.storage} />} />
            <Route path="/publicips"     element={<ResourceList title="Public IPs"              apiPath="/resources/publicips"     iconSrc={PAGE_ICONS.publicips} />} />
            <Route path="/loadbalancers" element={<ResourceList title="Load balancers"          apiPath="/resources/loadbalancers" iconSrc={PAGE_ICONS.loadbalancers} />} />
            <Route path="/appgateways"   element={<ResourceList title="Application gateways"   apiPath="/resources/appgateways"   iconSrc={PAGE_ICONS.appgateways} />} />
            <Route path="/nsgs"          element={<ResourceList title="Network security groups" apiPath="/resources/nsgs"          iconSrc={PAGE_ICONS.nsgs} />} />
            <Route path="/sql"           element={<ResourceList title="SQL servers"             apiPath="/resources/sql"           iconSrc={PAGE_ICONS.sql} />} />
            <Route path="/cosmosdb"      element={<ResourceList title="Cosmos DB accounts"      apiPath="/resources/cosmosdb"      iconSrc={PAGE_ICONS.cosmosdb} />} />
            <Route path="/postgresql"    element={<ResourceList title="PostgreSQL servers"      apiPath="/resources/postgresql"    iconSrc={PAGE_ICONS.postgresql} />} />
            <Route path="/keyvaults"     element={<ResourceList title="Key vaults"              apiPath="/resources/keyvaults"     iconSrc={PAGE_ICONS.keyvaults} />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
            </Suspense>
          </ErrorBoundary>
        </main>
      </div>
    </div>
  );
}

function AppRoutes() {
  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route
        path="/*"
        element={(
          <ProtectedRoute>
            <Shell />
          </ProtectedRoute>
        )}
      />
    </Routes>
  );
}

export default function App() {
  const [subscriptionRaw, setSubscriptionRaw] = usePersistedState('finops-subscription', '');
  const setSubscription = useCallback((value) => {
    setSubscriptionRaw(value ? String(value).trim().toLowerCase() : '');
  }, [setSubscriptionRaw]);
  const subscription = subscriptionRaw ? String(subscriptionRaw).trim().toLowerCase() : '';

  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [subscriptionError, setSubscriptionError] = useState('');

  const subscriptionOptions = useMemo(() => {
    const byId = new Map();
    subscriptions.forEach((s) => {
      if (s.subscriptionId) byId.set(s.subscriptionId, s);
    });
    if (subscription && !byId.has(subscription)) {
      byId.set(subscription, {
        subscriptionId: subscription,
        displayName: subscription,
        state: 'Synced',
      });
    }
    return Array.from(byId.values()).sort((a, b) =>
      (a.displayName || a.subscriptionId).localeCompare(b.displayName || b.subscriptionId),
    );
  }, [subscriptions, subscription]);

  const { data: costSummary } = useQuery({
    queryKey: ['cost-summary-meta', subscription],
    queryFn: () => fetchCostSummary({ subscription_id: subscription, timeframe: 'MonthToDate' }),
    enabled: !!subscription && !!getStoredToken(),
    staleTime: 30 * 60_000,
  });

  const billingCurrency = costSummary?.billing_currency || 'CAD';

  const loadSubscriptions = useCallback(() => {
    if (!getStoredToken()) {
      setSubscriptions([]);
      setLoading(false);
      return;
    }
    setLoading(true);
    fetchSubscriptions()
      .then((list) => {
        setSubscriptions(list);
        setSubscriptionError('');
        if (list.length > 0) {
          const ids = new Set(list.map((s) => s.subscriptionId));
          if (!subscription || !ids.has(subscription)) {
            setSubscription(list[0].subscriptionId);
          }
        }
      })
      .catch((err) => {
        setSubscriptionError(getErrorMessage(err, 'Could not load subscriptions.'));
      })
      .finally(() => setLoading(false));
  }, [setSubscription, subscription]);

  useEffect(() => {
    loadSubscriptions();
  }, [loadSubscriptions]);

  return (
    <QueryClientProvider client={qc}>
      <AuthProvider>
        <AppCtx.Provider value={{
          subscription,
          setSubscription,
          subscriptions,
          subscriptionOptions,
          loading,
          subscriptionError,
          reloadSubscriptions: loadSubscriptions,
          billingCurrency,
        }}>
          <BrowserRouter>
            <AppRoutes />
          </BrowserRouter>
        </AppCtx.Provider>
      </AuthProvider>
    </QueryClientProvider>
  );
}
